{"code":"import json
import re

papers_path = locals()['var_function-call-15031094012965990615']
with open(papers_path, 'r') as f:
    papers = json.load(f)

candidates = []

for p in papers:
    text = p['text']
    title = p['filename'].replace('.txt', '')

    region = text[:3000] + " " + text[-3000:]

    found_year = 0

    # Pattern 1
    m1 = re.search(r"(CHI|UbiComp|CSCW|DIS|IUI|OzCHI|TEI|AH)[^\d]*(\d{2,4})", region, re.IGNORECASE)
    if m1:
        y_str = m1.group(2)
        if len(y_str) == 2:
            found_year = 2000 + int(y_str)
        else:
            found_year = int(y_str)

    # Pattern 2
    if not found_year:
        m2 = re.search(r"(Copyright|©)[^0-9]*?(20\d{2})", region, re.IGNORECASE)
        if m2:
            found_year = int(m2.group(2))

    # Pattern 3
    if not found_year:
        m3 = re.search(r"(January|February|March|April|May|June|July|August|September|October|November|December)[^0-9]*?(20\d{2})", region, re.IGNORECASE)
        if m3:
            found_year = int(m3.group(2))

    is_empirical = "empirical" in text.lower()

    if found_year > 2016:
        candidates.append({
            "title": title,
            "year": found_year,
            "is_empirical": is_empirical
        })

print("__RESULT__:")
print(json.dumps(candidates))
"}

